    def validate_package_name(self, package_name: str) -> bool:
        """
        Validate package name against security rules.
        Prevents injection attacks and typosquatting.
        """
        # Check for valid package name format (PEP 508)
        pattern = r'^[a-zA-Z0-9]([a-zA-Z0-9._-]*[a-zA-Z0-9])?$'
        if not re.match(pattern, package_name):
            self.validation_errors.append(
                f"Invalid package name format: {package_name}"
            )
            return False
        
        # Check length to prevent DoS
        if len(package_name) > 100:
            self.validation_errors.append(
                f"Package name too long: {package_name}"
            )
            return False
        
        # Prevent common typosquatting patterns
        suspicious_patterns = [
            r'.*\d{4,}.*',  # Unusual number sequences
            r'.*[._-]{2,}.*',  # Multiple consecutive separators
        ]
        
        for pattern in suspicious_patterns:
            if re.match(pattern, package_name):
                self.validation_errors.append(
                    f"Suspicious package name pattern: {package_name}"
                )
                return False
        
        return True
    
    def is_approved_public_package(self, package_name: str) -> bool:
        """Check if package is in approved public package allowlist."""
